'use strict';

var fs = require('node:fs');
var path = require('node:path');
var constants = require('../constants.js');

function readFileContent(filePath, encoding = 'utf8') {
    const resolvedPath = path.resolve(filePath);
    if (!fs.existsSync(resolvedPath)) {
        return null;
    }
    return fs.readFileSync(resolvedPath, encoding);
}
function readJsonFile(filePath) {
    const fileContent = readFileContent(filePath);
    if (!fileContent) {
        return null;
    }
    return JSON.parse(fileContent);
}
function readDirPaths(dirPath) {
    const resolvedPath = path.resolve(dirPath);
    if (!fs.existsSync(resolvedPath)) {
        return null;
    }
    return fs
        .readdirSync(dirPath, { withFileTypes: true })
        .filter((dir) => dir.isDirectory())
        .map(({ parentPath, name }) => path.join(parentPath, name));
}
function readTranslationsDirs(srcPath) {
    return readDirPaths(srcPath);
}
function readMessagesFile(dirPath) {
    return readJsonFile(path.join(dirPath, 'messages.json'));
}
const LIB_TRANSLATIONS_PATH = path.resolve(constants.COMMON_DIR, constants.LIB_TRANSLATIONS_FILE);
function readLibTranslationDirs() {
    if (!fs.existsSync(LIB_TRANSLATIONS_PATH)) {
        return [];
    }
    return fs
        .readFileSync(LIB_TRANSLATIONS_PATH, 'utf8')
        .split('\n')
        .filter(Boolean); // Accept empty lines (EOF) and purge them
}

exports.readLibTranslationDirs = readLibTranslationDirs;
exports.readMessagesFile = readMessagesFile;
exports.readTranslationsDirs = readTranslationsDirs;
